var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"올바른 보도, 진실된 정보. 그로니아 국영 뉴스입니다.","JPN":"正しい報道、真なる情報。グロニア国営ニュースです。","ENG":"Reporting in with the truth, Gronia National News.","TWN":"真實的報導，正確的資訊，格羅尼亞國境新聞。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"정부는 건국절을 하루 앞둔 오늘, 타나베린에서 발생한 연속 붕괴 사고에 대해 유감을 표했습니다.","JPN":"政府は建国記念日の前日である今日、タナベリンで発生した連続崩壊事故に遺憾の意を表明しました。","ENG":"The government expressed its deep concern and sympathies towards the series of building collapses in Tanaberin, only a day before National Foundation Day.","TWN":"國慶日前夕，政府針對在達那貝林發生的連續崩毀事件表示遺憾。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"보안국은 이 사고가 반군과 무관하며, 일각에서 주장하는 갑옷 차림의 카운터는 집단 환각 현상임을 확인했습니다.","JPN":"保安局は今度の事故が反乱軍とは無関係であり、一部から主張されている鎧姿のカウンターは集団幻覚であることを確認しました。","ENG":"The Department of National Security confirmed that the incident was not connected in any way with the rebels. Claims of some seeing an armor-clad Counter at the incident, have been confirmed to be a collective hallucination.","TWN":"安全局表示此次事件與叛軍無關，至於部分目擊者看到的鎧甲裝扮制裁者，判定是集體產生的幻覺。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"다음 소식입니다. 우리 군의 용맹에 힘입어 반군과의 소요는 전년 대비 75% 감소하였고…….","JPN":"次のニュースです。勇猛なる我が国の軍の功績により、反乱軍との衝突は前年にくらべ75％減少し……","ENG":"Next up on the news. Thanks to the incredible bravery of our troops, terrorist attacks by the rebels are 75% lower than last year...","TWN":"下一則新聞，受到我軍英勇抗戰的影響，與叛軍的衝突大幅減少75%……"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"크으…….","JPN":"くぅ……","ENG":"Kgh...!","TWN":"呃……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"의식을 찾았는가. 몽타뉴. 몸이 매우 쇠약해진 상태였다.","JPN":"意識を取り戻したか。モンターニュ。体が非常に衰弱していた。","ENG":"Your consciousness has returned, Montagne. Your body condition was extremely weak.","TWN":"你醒了嗎，蒙塔妮？你的身體現在非常虛弱。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이것이 영혼의 조각으로 만든 약재라고 하더군. 도움이 될 것이다.","JPN":"これは魂の欠片で作られた薬材だそうだな。役に立つだろう。","ENG":"It is said that this medicine is made from soul fragments. It shall help you.","TWN":"這是用靈魂碎片製成的藥材，對你會有幫助的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"성흔을 지닌 자가 어찌하여 역병에 당하였는지는 묻지 않겠으나…….","JPN":"聖痕の持ち主が何故疫病にやられたのか、尋ねはしないが……","ENG":"I should not ask how one with a Stigmata suffered from the plague but...","TWN":"你不問我有聖痕的人為何會感染瘟疫嗎……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"왜지? 그림자?","JPN":"なんでだ？　シャドウ。","ENG":"Why is that? Shadow?","TWN":"為什麼要問？暗影？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"마에스트로에게 집착하는 것 아니었나?","JPN":"マエストロにこだわってなかったか？","ENG":"Aren’t you obsessed with Maestra?","TWN":"目標不是指揮家嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"본색이 드러나면 머리를 쪼개 버릴 작정 아니었어?","JPN":"本性が現れたら、頭を割るつもりじゃなかったのか。","ENG":"Weren’t you going to split her head open, once she revealed her true colors?","TWN":"等她一露出真面目，就要立刻砍下她的頭不是嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"간병 따위나 받자고…… 널 찾은 게 아니야.","JPN":"看病なんかされるために……あなたを探したわけじゃない。","ENG":"I didn’t work so hard to find you... just to receive medical attention.","TWN":"我找你來……不是來當看護的！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"내게 사람을 돌보는 재주는 없노라.","JPN":"我に人を看病する才能はない。","ENG":"The gift of looking after others, is not mine.","TWN":"我沒有當看護的天分。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너를 돌본 것은 네가 부리던 자들이로다.","JPN":"そなたを世話したのはそなたの配下たちだ。","ENG":"Those underlings of yours looked after you.","TWN":"照顧你的是之前跟你一起行動的那些人。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……. 그게, 저격수 나리가 죽으면 약 받을 사람도 없고…….","JPN":"へ、へへ……旦那が死んじゃったら薬をくれる人もいなくなるし……","ENG":"Heh, heh heh... if our sniper dies, there will be no one to give us any drug...","TWN":"嘿嘿嘿……那是因為姊死掉的話，就沒人可以給我們藥……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};